                    // C: OP_SHRI — rb >> sC (shift right by immediate)
                    // C: if (tointegerns(rb, &ib)) { pc++; setivalue(s2v(ra), luaV_shiftl(ib, -ic)); }
                    OpCode::ShrI => {
                        let ra = base + i.arg_a();
                        let v = state.get_at(base + i.arg_b()).clone();
                        let ic = i.arg_s_c() as i64;
