                    // C: op_orderI(L, l_lti/l_lei/l_gti/l_gei, luai_numlt/le/gt/ge,
                    //              inv=0/0/1/1, tm=TM_LT/TM_LE/TM_LT/TM_LE)
                    OpCode::LtI => {
                        order_imm_op(state, &cl, &mut pc, &mut trap, ci, base, i,
                            |a: i64, b: i64| a < b, |a: f64, b: f64| a < b,
                            false, TagMethod::Lt)?;
                    }
                    OpCode::LeI => {
                        order_imm_op(state, &cl, &mut pc, &mut trap, ci, base, i,
                            |a: i64, b: i64| a <= b, |a: f64, b: f64| a <= b,
                            false, TagMethod::Le)?;
                    }
                    OpCode::GtI => {
                        order_imm_op(state, &cl, &mut pc, &mut trap, ci, base, i,
                            |a: i64, b: i64| a > b, |a: f64, b: f64| a > b,
                            true, TagMethod::Lt)?;
                    }
                    OpCode::GeI => {
