                    OpCode::SetI => {
                        let ra_v = state.get_at(base + i.arg_a()).clone();
                        let c = i.arg_b() as i64;
                        let rc_v = if i.test_k() {
                            state.proto_const(&cl, i.arg_c() as usize).clone()
                        } else {
                            state.get_at(base + i.arg_c()).clone()
                        };
