                            let extra = state.proto_code(&cl, pc);
                            pc += 1;
                            // C: c += GETARG_Ax(*pc) * (MAXARG_C + 1)
                            const MAXARG_C: i32 = (1 << 8) - 1;
                            c += extra.arg_ax() * (MAXARG_C + 1);
