1686	/// Discharge `e` into the specific register `reg`. Mirrors C's `exp2reg`
1687	/// from `lcode.c`: delegates to `cg_discharge_to_reg`, then folds the jump
1688	/// at `e.u.info` into `e.t` (when `e` is itself a test) and patches any
1689	/// pending `e.t` / `e.f` jump-lists. When the lists actually need a value
1690	/// (i.e. any controller isn't a `TESTSET`), emits the LFalseSkip / LoadTrue
1691	/// pair around which the jumps land.
1692	fn cg_exp_to_reg(
1693	    fs: &mut FuncState,
1694	    line: i32,
1695	    e: &mut ExprDesc,
1696	    reg: u8,
1697	) -> Result<(), LuaError> {
1698	    cg_discharge_to_reg(fs, line, e, reg)?;
1699	    if e.k == ExprKind::Jmp {
1700	        let info = e.u.info;
1701	        cg_concat(fs, &mut e.t, info)?;
1702	    }
1703	    if e.t != e.f {
1704	        let mut p_f = NO_JUMP;
1705	        let mut p_t = NO_JUMP;
1706	        if cg_need_value(fs, e.t) || cg_need_value(fs, e.f) {
1707	            let fj = if e.k == ExprKind::Jmp {
1708	                NO_JUMP
1709	            } else {
1710	                cg_jump(fs, line)
1711	            };
1712	            p_f = cg_code_loadbool(fs, line, reg as i32, lua_code::opcodes::OpCode::LFalseSkip);
1713	            p_t = cg_code_loadbool(fs, line, reg as i32, lua_code::opcodes::OpCode::LoadTrue);
1714	            cg_patch_to_here(fs, fj)?;
1715	        }
1716	        let final_pc = cg_get_label(fs);
1717	        cg_patch_list_aux(fs, e.f, final_pc, reg as u32, p_f)?;
1718	        cg_patch_list_aux(fs, e.t, final_pc, reg as u32, p_t)?;
1719	    }
1720	    e.f = NO_JUMP;
1721	    e.t = NO_JUMP;
1722	    e.u.info = reg as i32;
1723	    e.k = ExprKind::NonReloc;
1724	    Ok(())
1725	}
