1771	/// `OP_JMP` instructions to the final landing pc. Capped at 100 hops to
1772	/// avoid infinite loops on malformed code.
1773	fn cg_final_target(fs: &FuncState, mut i: i32) -> i32 {
1774	    for _ in 0..100 {
1775	        let inst = cg_inst_at(fs, i);
1776	        if inst.opcode() != Some(lua_code::opcodes::OpCode::Jmp) {
